const CONFIG={MANIFEST_URL:'file-list.json',CACHE_NAME_PREFIX:'precache',DYNAMIC_CACHE_NAME:'dynamic-content',NETWORK_TIMEOUT_MS:3000,MAX_DYNAMIC_ENTRIES:50,DEBUG:true};const ORIGIN=self.location.origin;const log=(...args)=>CONFIG.DEBUG&&console.log('[SW]',...args);const warn=(...args)=>CONFIG.DEBUG&&console.warn('[SW]',...args);const error=(...args)=>CONFIG.DEBUG&&console.error('[SW]',...args);const WORKBOX_SCRIPTS=['/scripts/workbox-core.prod.js','/scripts/workbox-routing.prod.js','/scripts/workbox-strategies.prod.js','/scripts/workbox-cacheable-response.prod.js','/scripts/workbox-expiration.prod.js','/scripts/workbox-background-sync.prod.js'];try{log('init','Loading Workbox modules from local /scripts/...');WORKBOX_SCRIPTS.forEach(scriptPath=>{try{importScripts(scriptPath);if(CONFIG.DEBUG){console.debug(`[SW] Loaded: ${ scriptPath }`)}}catch(e){console.error(`[SW] ERROR loading ${ scriptPath }:`,e);throw new Error(`Failed to load ${ scriptPath }. Ensure files exist.`)}});log('init','All Workbox modules loaded successfully.');const wbRouting=workbox.routing;const wbStrategies=workbox.strategies;const wbCacheable=workbox.cacheableResponse;const wbExpiration=workbox.expiration;const wbBgSync=workbox.backgroundSync}catch(error){console.error('[SW] FATAL: Workbox initialization failed.',error);throw new Error('Service Worker Initialization Failed: Missing Workbox Libraries')}let currentCacheName='';const precacheAllowList=new Map();let warmUpUrls=[];let strategiesInitialized=false;let cacheFirstHandler,networkFirstHandler,dynamicHandler;function normalizeUrl(url){try{const u=new URL(url,ORIGIN);return u.href}catch{return null}}function createCacheKey(url,revision){const parsed=new URL(url,ORIGIN);if(revision){parsed.searchParams.set('__rev',revision)}return parsed.href}async function loadManifest(){let response;try{response=await fetch(CONFIG.MANIFEST_URL,{cache:'no-cache'})}catch(e){throw new Error(`Failed to fetch manifest: Network error (${e.message })`)}if(!response.ok){throw new Error(`Failed to fetch manifest: HTTP ${response.status }`)}const manifest=await response.json();const{version,defaultRevision,groups=[],warmUp=[]}=manifest;currentCacheName=`${CONFIG.CACHE_NAME_PREFIX }-v${ version }`;warmUpUrls=warmUp.map(u=>normalizeUrl(u)).filter(Boolean);const entries=[];for(const group of groups||[]){if(group.strategy!=='precache'){continue}for(const file of group.files??[]){const revision=file.revision??defaultRevision;const normalizedUrl=normalizeUrl(file.url);if(!normalizedUrl){warn('manifest','Skipping invalid URL in manifest:',file.url);continue}const cacheKey=createCacheKey(file.url,revision);precacheAllowList.set(normalizedUrl,cacheKey);entries.push({url:file.url,cacheKey,normalizedUrl})}}log('manifest',`Loaded ${entries.length } precache entries for version ${ version }`);return entries}async function precacheAssets(){const entries=await loadManifest();if(entries.length===0){log('install','No assets defined in manifest to precache.');return}log('install',`Starting precache: ${entries.length } assets into '${ currentCacheName }'`);const cache=await caches.open(currentCacheName);let successCount=0;let failureCount=0;const failedEntries=[];const results=await Promise.allSettled(entries.map(async({url,cacheKey})=>{try{const response=await fetch(url,{cache:'no-cache'});if(!response.ok){throw new Error(`HTTP ${response.status }`)}await cache.put(cacheKey,response);return{success:true,url}}catch(err){return{success:false,url,error:err.message}}}));results.forEach((result)=>{if(result.success){successCount+=1}else{failureCount+=1;failedEntries.push(result.url);warn('install',`Failed to cache: ${result.url }`,result.error)}});log('install',`Precache Summary: ${ successCount }/${entries.length } succeeded.`);if(failureCount===entries.length){throw new Error('CRITICAL FAILURE: All precache requests failed. Installation aborted.')}if(failureCount>0){warn('install',`${ failureCount } assets failed. Check logs for details.`)}}async function cleanupStaleCaches(){const keys=await caches.keys();const prefixPattern=new RegExp(`^${CONFIG.CACHE_NAME_PREFIX }-v\\d+$`);const validCacheNames=[currentCacheName,CONFIG.DYNAMIC_CACHE_NAME];let deletedCount=0;for(const key of keys){let shouldDelete=false;let reason='';if(prefixPattern.test(key)){if(key!==currentCacheName){shouldDelete=true;reason=`Old precache version`}}else if(!validCacheNames.includes(key)){shouldDelete=true;reason=`Unrecognized cache`}if(shouldDelete){log('activate',`Deleting stale cache: ${ key } (${ reason })`);await caches.delete(key);deletedCount+=1}}if(deletedCount>0){log('activate',`Cleanup complete. Deleted ${ deletedCount } caches.`)}}async function initStrategies(){if(strategiesInitialized){return}if(!wbStrategies||!wbCacheable){throw new Error("Workbox modules not detected. Check importScripts.")}const cacheablePlugin=new wbCacheable.CacheableResponsePlugin({statuses:[0,200]});const expirationPlugin=new wbExpiration.ExpirationPlugin({maxEntries:CONFIG.MAX_DYNAMIC_ENTRIES,purgeOnQuotaError:true});const bgSyncPlugin=new wbBgSync.BackgroundSyncPlugin('post-sync-queue',{maxRetentionTime:24*60,onSync:async({queue})=>{let entry;while((entry=await queue.shiftRequest())){try{await fetch(entry.request);log('bg-sync',`Replayed successfully: ${entry.request.url }`)}catch(err){await queue.unshiftRequest(entry);log('bg-sync',`Replay failed for ${entry.request.url }, re-queued.`,err.message);}}}});cacheFirstHandler=new wbStrategies.CacheFirst({cacheName:currentCacheName,plugins:[cacheablePlugin]});networkFirstHandler=new wbStrategies.NetworkFirst({cacheName:currentCacheName,networkTimeoutSeconds:Math.ceil(CONFIG.NETWORK_TIMEOUT_MS/1000),plugins:[cacheablePlugin]});dynamicHandler=new wbStrategies.NetworkFirst({cacheName:CONFIG.DYNAMIC_CACHE_NAME,networkTimeoutSeconds:Math.ceil(CONFIG.NETWORK_TIMEOUT_MS/1000),plugins:[cacheablePlugin,expirationPlugin,bgSyncPlugin]});strategiesInitialized=true;log('init','All caching strategies initialized.')}async function warmUpCache(){if(warmUpUrls.length===0){return}log('warming',`Triggering idle warm-up for ${warmUpUrls.length } URLs`);const cache=await caches.open(currentCacheName);for(const url of warmUpUrls){if(await cache.match(url)){continue}try{const response=await fetch(url,{cache:'no-cache'});if(response.ok){await cache.put(url,response);log('warming',`Warmed up: ${ url }`)}else{warn('warming',`Warmup failed for ${ url }: HTTP ${response.status }`)}}catch(err){warn('warming',`Warmup network error for ${ url }:`,err.message)}}}function triggerWarmUp(){if('requestIdleCallback'in self){requestIdleCallback(warmUpCache,{timeout:5000})}else{setTimeout(warmUpCache,5000)}}self.addEventListener('install',(event)=>{event.waitUntil(precacheAssets().then(()=>{log('install','Precaching finished successfully.');return self.skipWaiting()}).catch((err)=>{error('install','Installation failed:',err.message);}))});self.addEventListener('activate',(event)=>{event.waitUntil(cleanupStaleCaches().then(()=>{log('activate','Stale cache cleanup finished.');return self.clients.claim()}).then(()=>initStrategies()).then(()=>{log('activate','Service Worker fully active and ready.')}))});self.addEventListener('fetch',(event)=>{if(event.request.method!=='GET'){return}if(!strategiesInitialized){if(CONFIG.DEBUG){console.debug('[SW] Fetch intercepted before init, passing through.')}return}const normalizedUrl=normalizeUrl(event.request.url);const cacheKey=normalizedUrl?precacheAllowList.get(normalizedUrl):null;if(cacheKey){if(isNavigationRequest(event.request)){event.respondWith(networkFirstHandler.handle({request:event.request}).catch(()=>{return caches.open(currentCacheName).then(cache=>cache.match(cacheKey))}))}else{event.respondWith(cacheFirstHandler.handle({request:event.request}))}}else{if(isNavigationRequest(event.request)){event.respondWith(networkFirstHandler.handle({request:event.request}).catch(async()=>{const offlinePage=await caches.match('/offline.html');if(offlinePage){return offlinePage}const rootKey=precacheAllowList.get(normalizeUrl('/'));if(rootKey){const cache=await caches.open(currentCacheName);return cache.match(rootKey)}return Response.error()}))}else{event.respondWith(dynamicHandler.handle({request:event.request}))}}if(!self.warmupTriggered){self.warmupTriggered=true;setTimeout(triggerWarmUp,2000)}});function isNavigationRequest(request){return request.mode==='navigate'||request.headers.get('accept')?.includes('text/html');}
